for expected_outcome, expected_prob in expected_counts.items():
    if expected_outcome in observed_counts:
        observed_prob = observed_counts[expected_outcome]
        assert abs(observed_prob - expected_prob) < 0.1, f"Probability for {expected_outcome} deviates too much: {observed_prob}"
